123	      });
124	  }, [keybindingsConfigPath]);
125	
126	  const addCustomModel = useCallback((provider: ProviderKind) => {
127	    const customModelInput = customModelInputByProvider[provider];
128	    const customModels = getCustomModelsForProvider(settings, provider);
129	    const normalized = normalizeModelSlug(customModelInput, provider);
130	    if (!normalized) {
131	      setCustomModelErrorByProvider((existing) => ({
132	        ...existing,
133	        [provider]: "Enter a model slug.",
134	      }));
135	      return;
136	    }
137	    if (getModelOptions(provider).some((option) => option.slug === normalized)) {
138	      setCustomModelErrorByProvider((existing) => ({
139	        ...existing,
140	        [provider]: "That model is already built in.",
141	      }));
142	      return;
143	    }
144	    if (normalized.length > MAX_CUSTOM_MODEL_LENGTH) {
145	      setCustomModelErrorByProvider((existing) => ({
146	        ...existing,
147	        [provider]: `Model slugs must be ${MAX_CUSTOM_MODEL_LENGTH} characters or less.`,
148	      }));
149	      return;
150	    }
151	    if (customModels.includes(normalized)) {
152	      setCustomModelErrorByProvider((existing) => ({
153	        ...existing,
154	        [provider]: "That custom model is already saved.",
155	      }));
156	      return;
157	    }
158	
159	    updateSettings(patchCustomModels(provider, [...customModels, normalized]));
160	    setCustomModelInputByProvider((existing) => ({
161	      ...existing,
162	      [provider]: "",
163	    }));
164	    setCustomModelErrorByProvider((existing) => ({
165	      ...existing,
166	      [provider]: null,
167	    }));
168	  }, [customModelInputByProvider, settings, updateSettings]);
169	
170	  const removeCustomModel = useCallback(
171	    (provider: ProviderKind, slug: string) => {
172	      const customModels = getCustomModelsForProvider(settings, provider);
173	      updateSettings(patchCustomModels(provider, customModels.filter((model) => model !== slug)));
174	      setCustomModelErrorByProvider((existing) => ({
175	        ...existing,
176	        [provider]: null,
177	      }));
178	    },
179	    [settings, updateSettings],
180	  );
181	
182	  return (
183	    <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground isolate">
184	      <div className="flex min-h-0 min-w-0 flex-1 flex-col bg-background text-foreground">
185	        {isElectron && (
186	          <div className="drag-region flex h-[52px] shrink-0 items-center border-b border-border px-5">
187	            <span className="text-xs font-medium tracking-wide text-muted-foreground/70">
188	              Settings
189	            </span>
190	          </div>
191	        )}
192	
193	        <div className="flex-1 overflow-y-auto p-6">
194	          <div className="mx-auto flex w-full max-w-3xl flex-col gap-6">
195	            <header className="space-y-1">
196	              <h1 className="text-2xl font-semibold tracking-tight text-foreground">Settings</h1>
197	              <p className="text-sm text-muted-foreground">
198	                Configure app-level preferences for this device.
199	              </p>
200	            </header>
201	
202	            <section className="rounded-2xl border border-border bg-card p-5">
203	              <div className="mb-4">
204	                <h2 className="text-sm font-medium text-foreground">Appearance</h2>
205	                <p className="mt-1 text-xs text-muted-foreground">
206	                  Choose how T3 Code handles light and dark mode.
207	                </p>
208	              </div>
209	
210	              <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
211	                {THEME_OPTIONS.map((option) => {
