import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:color-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";

// Resolved once at module load – guaranteed to exist for built-in IDs.
const FALLBACK_THEME: Theme = getTheme(DEFAULT_THEME_ID)!;

// ---------------------------------------------------------------------------
// CSS custom-property helpers
// ---------------------------------------------------------------------------

/**
 * Determine whether a hex colour (`#RRGGBB`) is perceptually dark using the
 * W3C relative-luminance formula.
 */
function isBackgroundDark(hex: string): boolean {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 < 0.5;
}

/**
 * Derive a complete set of CSS custom properties from a {@link Theme}.
 *
 * The seven semantic theme colours are mapped onto the lower-level variables
 * consumed by Tailwind utility classes (`bg-background`, `text-foreground`,
 * etc.) so the entire palette updates when the theme changes.
 */
function buildCSSProperties(theme: Theme): Record<string, string> {
  const isDark = isBackgroundDark(theme.colors.background);
  const { background, foreground, accent, sidebar, editor } = theme.colors;

  return {
    "--background": background,
    "--foreground": foreground,
    "--primary": accent,
    "--primary-foreground": "#ffffff",
    "--ring": accent,
    "--card": sidebar,
    "--card-foreground": foreground,
    "--popover": editor,
    "--popover-foreground": foreground,
    "--muted": isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)",
    "--muted-foreground": isDark ? "#818181" : "#676767",
    "--accent": isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)",
    "--accent-foreground": foreground,
    "--secondary": isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)",
    "--secondary-foreground": foreground,
    "--border": isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.08)",
    "--input": isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.10)",
    "--destructive": isDark ? "#f15757" : "#ef4444",
    "--destructive-foreground": isDark ? "#fca5a5" : "#b91c1c",
    "--info": "#3b82f6",
    "--info-foreground": isDark ? "#60a5fa" : "#1d4ed8",
    "--success": "#10b981",
    "--success-foreground": isDark ? "#34d399" : "#047857",
    "--warning": "#f59e0b",
    "--warning-foreground": isDark ? "#fbbf24" : "#b45309",
  };
}

/**
 * Apply a {@link Theme} to the document root element.
 *
 * Sets CSS custom properties as inline styles (highest cascade priority) and
 * toggles the `.dark` class used by the Tailwind `dark:` variant.
 */
function applyThemeToDOM(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle Tailwind dark variant class & colour-scheme
  const isDark = isBackgroundDark(theme.colors.background);
  root.classList.toggle("dark", isDark);
  root.style.colorScheme = isDark ? "dark" : "light";

  // Apply all CSS custom properties as inline styles
  for (const [key, value] of Object.entries(buildCSSProperties(theme))) {
    root.style.setProperty(key, value);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// External store (module-level state for useSyncExternalStore)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];

interface ThemeSnapshot {
  themeId: string;
  theme: Theme;
}

let lastSnapshot: ThemeSnapshot | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

/** Read the persisted theme ID, migrating from the legacy key if necessary. */
function resolveStoredThemeId(): string {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored && getTheme(stored)) return stored;

  // Migrate from the legacy light / dark / system key
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === "light") return "t3-light";
  if (legacy === "dark") return "t3-dark";
  if (legacy === "system") {
    return window.matchMedia("(prefers-color-scheme: dark)").matches
      ? "t3-dark"
      : "t3-light";
  }

  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? FALLBACK_THEME;
}

function getSnapshot(): ThemeSnapshot {
  const themeId = resolveStoredThemeId();
  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }
  lastSnapshot = { themeId, theme: resolveTheme(themeId) };
  return lastSnapshot;
}

const SERVER_SNAPSHOT: ThemeSnapshot = {
  themeId: DEFAULT_THEME_ID,
  theme: FALLBACK_THEME,
};

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync across tabs via storage events
  const handleStorage = (event: StorageEvent) => {
    if (event.key === STORAGE_KEY || event.key === LEGACY_STORAGE_KEY) {
      applyThemeToDOM(resolveTheme(resolveStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// Apply immediately on module load to prevent flash of unstyled content.
applyThemeToDOM(resolveTheme(resolveStoredThemeId()));

// ---------------------------------------------------------------------------
// React hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(
    subscribe,
    getSnapshot,
    () => SERVER_SNAPSHOT,
  );

  const resolvedTheme: "light" | "dark" = isBackgroundDark(
    snapshot.theme.colors.background,
  )
    ? "dark"
    : "light";

  const setTheme = useCallback((id: string) => {
    const theme = resolveTheme(id);
    localStorage.setItem(STORAGE_KEY, theme.id);
    applyThemeToDOM(theme, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount / when the snapshot changes
  useEffect(() => {
    applyThemeToDOM(snapshot.theme);
  }, [snapshot.theme]);

  return {
    /** The currently active {@link Theme} object. */
    theme: snapshot.theme,
    /** Switch to a different theme by its `id`. */
    setTheme,
    /** All themes available for selection. */
    availableThemes: listThemes(),
    /** Whether the active theme is `"light"` or `"dark"`. */
    resolvedTheme,
  } as const;
}

