import { type Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";
import { cn } from "~/lib/utils";

/** Mini editor preview showing the theme's colour palette. */
function ThemeSwatch({ theme: t }: { readonly theme: Theme }) {
  return (
    <div
      className="flex h-9 w-16 shrink-0 overflow-hidden rounded-md shadow-xs"
      style={{ outline: "1px solid rgba(128,128,128,0.18)" }}
      aria-hidden="true"
    >
      {/* Sidebar strip */}
      <div
        className="flex w-4 shrink-0 flex-col gap-0.5 px-0.5 pt-1.5"
        style={{ backgroundColor: t.colors.sidebar }}
      >
        <div
          className="h-0.5 rounded-full"
          style={{ backgroundColor: t.colors.accent }}
        />
        <div
          className="h-0.5 w-2/3 rounded-full"
          style={{ backgroundColor: t.colors.foreground, opacity: 0.3 }}
        />
      </div>
      {/* Editor area + status bar */}
      <div className="flex flex-1 flex-col">
        <div
          className="flex-1 px-0.5 pt-1"
          style={{ backgroundColor: t.colors.editor }}
        >
          <div
            className="h-0.5 w-full rounded-full"
            style={{ backgroundColor: t.colors.foreground, opacity: 0.2 }}
          />
          <div
            className="mt-0.5 h-0.5 w-2/3 rounded-full"
            style={{ backgroundColor: t.colors.foreground, opacity: 0.12 }}
          />
        </div>
        <div
          className="h-1.5 shrink-0"
          style={{ backgroundColor: t.colors.statusBar }}
        />
      </div>
    </div>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, availableThemes, resolvedTheme } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Color theme">
        {availableThemes.map((t) => {
          const selected = theme.id === t.id;
          return (
            <button
              key={t.id}
              type="button"
              role="radio"
              aria-checked={selected}
              className={cn(
                "flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent",
              )}
              onClick={() => setTheme(t.id)}
            >
              <ThemeSwatch theme={t} />
              <span className="flex-1 text-sm font-medium">{t.name}</span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active mode:{" "}
        <span className="font-medium text-foreground">{resolvedTheme}</span>
      </p>
    </div>
  );
}

