export interface ThemeColors {
  /** Main application background */
  background: string;
  /** Primary text color */
  foreground: string;
  /** Accent / brand color for interactive elements */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Editor / main content area background */
  editor: string;
  /** Terminal panel background */
  terminal: string;
  /** Status bar background */
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

export const DEFAULT_THEME_ID = "t3-dark";

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#161616",
      foreground: "#f5f5f5",
      accent: "#6366f1",
      sidebar: "#1a1a1a",
      editor: "#1a1a1a",
      terminal: "#161616",
      statusBar: "#1a1a1a",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "#4f46e5",
      sidebar: "#f9fafb",
      editor: "#ffffff",
      terminal: "#f3f4f6",
      statusBar: "#f3f4f6",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0b1120",
      foreground: "#e2e8f0",
      accent: "#818cf8",
      sidebar: "#0f172a",
      editor: "#0d1526",
      terminal: "#0b1120",
      statusBar: "#1e293b",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}
